@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService Recipes

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipeList.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipeList)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating / 5
                            <small>(@recipe.Ratings.Count ratings)</small>
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private List<RecipeShare.Models.Recipe> recipeList = [];

    protected override void OnParametersSet()
    {
        recipeList = Recipes.GetByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeShare.Services
@inject RecipeService Recipes

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
    <a href="/" class="btn btn-link">← Back to Home</a>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h4>Steps</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>

    <div class="card mt-4">
        <div class="card-body">
            <h5>Rate this Recipe</h5>
            <p class="text-muted mb-2">
                Average: ⭐ @recipe.AverageRating / 5
                (@recipe.Ratings.Count ratings)
            </p>
            <StarRating RecipeId="recipe.Id" />
        </div>
    </div>

    <a href="category/@recipe.Category" class="btn btn-link mt-3">← Back to @recipe.Category Recipes</a>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = Recipes.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService Recipes

<div>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                disabled="@hasRated"
                title="Rate @star stars">
            @(star <= (hoverRating > 0 ? hoverRating : currentRating) ? "★" : "☆")
        </button>
    }

    @if (hasRated)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int currentRating;
    private int hoverRating;
    private bool hasRated;

    private void SubmitRating(int rating)
    {
        if (hasRated) return;
        currentRating = rating;
        Recipes.AddRating(RecipeId, rating);
        hasRated = true;
    }
}

