using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Recipe title is required.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be 3–100 characters.")]
    public string? Title { get; set; }

    [Required(ErrorMessage = "Please select a category.")]
    public string? Category { get; set; }

    [Required(ErrorMessage = "Please provide a short description.")]
    [StringLength(300, MinimumLength = 10, ErrorMessage = "Description must be 10–300 characters.")]
    public string? Description { get; set; }

    [Required(ErrorMessage = "Please list at least one ingredient.")]
    [MinLength(1, ErrorMessage = "Please list at least one ingredient.")]
    public string? Ingredients { get; set; }

    [Required(ErrorMessage = "Please describe the steps.")]
    [MinLength(1, ErrorMessage = "Please describe at least one step.")]
    public string? Steps { get; set; }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService Recipes
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted!</h4>
        <p>Your recipe "<strong>@Model!.Title</strong>" has been added.</p>
        <a href="recipe/@submittedId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText @bind-Value="Model!.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => Model!.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect @bind-Value="Model!.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in Recipes.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="American">American</option>
                <option value="French">French</option>
                <option value="Japanese">Japanese</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Model!.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label class="form-label">Description</label>
            <InputTextArea @bind-Value="Model!.Description" class="form-control" rows="2"
                           placeholder="A short description of your recipe" />
            <ValidationMessage For="() => Model!.Description" class="text-danger" />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients <small class="text-muted">(one per line)</small></label>
            <InputTextArea @bind-Value="Model!.Ingredients" class="form-control" rows="5"
                           placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
            <ValidationMessage For="() => Model!.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps <small class="text-muted">(one per line)</small></label>
            <InputTextArea @bind-Value="Model!.Steps" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;..." />
            <ValidationMessage For="() => Model!.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Submit Recipe")
        </button>
        <a href="/" class="btn btn-link">Cancel</a>
    </EditForm>
}

@code {
    private RecipeFormModel? Model { get; set; }
    private bool submitted;
    private bool isSubmitting;
    private int submittedId;

    protected override void OnInitialized() => Model ??= new();

    private void HandleSubmit()
    {
        isSubmitting = true;

        var recipe = new Recipe
        {
            Title = Model!.Title!,
            Category = Model.Category!,
            Description = Model.Description!,
            Ingredients = Model.Ingredients!
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = Model.Steps!
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        Recipes.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
        isSubmitting = false;
    }

    private void ResetForm()
    {
        Model = new();
        submitted = false;
    }
}

